sql:
SELECT valid_count, invalid_count
FROM valid_entry_counts
WHERE report_date = '2023-03-16';

SELECT t.entry_id, t.time, v.report_date, v.valid_count
FROM time_series_data t
JOIN valid_entry_counts v ON t.entry_id = v.count_id;

SELECT SUM(valid_count) AS TotalValidEntries
FROM valid_entry_counts
WHERE report_date = '2023-03-15';

SELECT valid_count, invalid_count, total_entries
FROM valid_entry_counts
ORDER BY report_date DESC;

SELECT users.user_name, users.email, users.role
FROM users
INNER JOIN data_access_logs ON users.user_id = data_access_logs.user_id;

external_knowledge:
- The year 2000 or later is considered 'recent years' in this context; 
- May (5) or later refers to the middle of the year onwards; 
- The 15th or later in a month refers to the second half of the month.

sql:
SELECT report_date, SUM(total_entries) AS total_entries, SUM(valid_count) AS total_valid, SUM(invalid_count) AS total_invalid
FROM valid_entry_counts
WHERE report_date = '2023-03-16';
